def multiplcation_table(n):
    tabel = []
    for i in range(1, n + 1):
        row = []
        for j in range(1, n + 1):
            row.append(i * j)
        tabel.append(row)
    return tabel
This goes through every i and j from 1 to n and multiplies them, putting each row into the tabel list one at a time.
